# Error detail builder
class ErrorDetailBuilder:
    @staticmethod
    def build_error_details(exception, context, include_internal_state=True, internal_state=None):
        error_details = {
            "timestamp": datetime.datetime.utcnow().isoformat(),
            "exception_type": type(exception).__name__,
            "exception_message": str(exception),
            "traceback": traceback.format_exc(),
            "stack_trace": traceback.format_stack(),
        }
        
        if include_internal_state and internal_state:
            error_details["internal_state"] = internal_state
        
        if hasattr(exception, '__dict__'):
            error_details["exception_attributes"] = {
                k: str(v) for k, v in exception.__dict__.items()
            }
        
        error_details["python_version"] = sys.version
        error_details["context_info"] = {
            "peer": context.peer() if context else "unknown",
            "method": context._rpc_event.call_details.method if context and hasattr(context, '_rpc_event') else "unknown"
        }
        
        return json.dumps(error_details, indent=2, default=str)

# Base service class with error handling
class ServiceWithErrorHandling:
    def __init__(self, service_name="UnknownService"):
        self.service_name = service_name
        self.internal_state = {}
        self.logger = logging.getLogger(service_name)
        logging.basicConfig(level=logging.INFO)
    
    def handle_error(self, exception, context, method_name, additional_state=None):
        self.logger.error(f"Error in {method_name}: {str(exception)}")
        
        internal_state = {
            "service_name": self.service_name,
            "method_name": method_name,
            "service_state": self.internal_state.copy()
        }
        
        if additional_state:
            internal_state["method_state"] = additional_state
        
        error_details = ErrorDetailBuilder.build_error_details(
            exception, 
            context, 
            include_internal_state=True,
            internal_state=internal_state
        )
        
        if isinstance(exception, ValueError):
            context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
            context.set_details(f"Invalid argument error in {method_name}:\n{error_details}")
        elif isinstance(exception, KeyError):
            context.set_code(grpc.StatusCode.NOT_FOUND)
            context.set_details(f"Resource not found in {method_name}:\n{error_details}")
        elif isinstance(exception, PermissionError):
            context.set_code(grpc.StatusCode.PERMISSION_DENIED)
            context.set_details(f"Permission denied in {method_name}:\n{error_details}")
        elif isinstance(exception, TimeoutError):
            context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
            context.set_details(f"Timeout in {method_name}:\n{error_details}")
        elif isinstance(exception, NotImplementedError):
            context.set_code(grpc.StatusCode.UNIMPLEMENTED)
            context.set_details(f"Not implemented in {method_name}:\n{error_details}")
        elif isinstance(exception, ConnectionError):
            context.set_code(grpc.StatusCode.UNAVAILABLE)
            context.set_details(f"Service unavailable in {method_name}:\n{error_details}")
        elif isinstance(exception, MemoryError):
            context.set_code(grpc.StatusCode.RESOURCE_EXHAUSTED)
            context.set_details(f"Resource exhausted in {method_name}:\n{error_details}")
        else:
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details(f"Internal error in {method_name}:\n{error_details}")
        
        return None

